1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: Cell[] = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const shouldLive = (liveNeighborCount: number, isCurrentlyAlive: boolean): boolean =>
15	  liveNeighborCount === 3 || (liveNeighborCount === 2 && isCurrentlyAlive);
16	
17	export function nextGeneration(livingCells: Cell[]): Cell[] {
18	  const liveKeys = new Set(livingCells.map(cellKey));
19	  const candidates = new Map<string, { cell: Cell; liveNeighborCount: number }>();
20	
21	  for (const cell of livingCells) {
22	    for (const neighbor of neighborsOf(cell)) {
23	      const k = cellKey(neighbor);
24	      const existing = candidates.get(k);
25	      if (existing) existing.liveNeighborCount++;
26	      else candidates.set(k, { cell: neighbor, liveNeighborCount: 1 });
27	    }
28	  }
29	
30	  const result: Cell[] = [];
31	  for (const [k, { cell, liveNeighborCount }] of candidates) {
32	    if (shouldLive(liveNeighborCount, liveKeys.has(k))) result.push(cell);
33	  }
34	  return result;
35	}
36

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  // Degenerate base case
6	  it("should return [] for an empty input (no living cells)", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	
10	  // Rule 1 - Underpopulation
11	  it("should kill a single isolated cell with 0 neighbors — [(0,0)] → []", () => {
12	    expect(nextGeneration([[0, 0]])).toEqual([]);
13	  });
14	  it("should kill two adjacent cells each with 1 neighbor (underpopulation) — [(0,1),(1,1)] → []", () => {
15	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
16	  });
17	
18	  // Block still life (survival with 3 neighbors each)
19	  it("should keep a 2x2 block unchanged (still life) — [(0,0),(1,0),(0,1),(1,1)] → same set", () => {
20	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
21	    expect(result).toHaveLength(4);
22	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
23	  });
24	
25	  // Rule 2 - Survival: a live cell with 2 neighbors survives (vertical blinker center)
26	  it("should let live center cell (0,1) with 2 live neighbors survive — Rule 2", () => {
27	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
28	    expect(result).toEqual(expect.arrayContaining([[0, 1]]));
29	  });
30	
31	  // Rule 4 - Reproduction
32	  it("should bring dead cell (1,1) to life when it has exactly 3 live neighbors (L-shape) — Rule 4: [(0,0),(1,0),(0,1)] produces (1,1) alive", () => {
33	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
34	    expect(result).toEqual(expect.arrayContaining([[1, 1]]));
35	  });
36	
37	  // Rule 3 - Overpopulation
38	  it("should kill center cell (1,1) with 4 live neighbors (full 3x3 ring + center) — Rule 3", () => {
39	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]]);
40	    expect(result).not.toEqual(expect.arrayContaining([[1, 1]]));
41	  });
42	
43	  // Blinker oscillator - vertical to horizontal
44	  it("should oscillate a vertical blinker into a horizontal one — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
45	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
46	    expect(result).toHaveLength(3);
47	    expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]]));
48	  });
49	
50	  // Negative coordinates
51	  it.todo("should handle negative coordinates correctly (blinker output contains (-1,1) — verifies infinite grid in negative direction)");
52	});
